import type { UmbConditionControllerArguments, UmbExtensionCondition } from '@umbraco-cms/backoffice/extension-api';
import { UmbConditionBase } from '@umbraco-cms/backoffice/extension-registry';
import type { UmbControllerHost } from '@umbraco-cms/backoffice/controller-api';
import type { FormsDataSourceCreatedConditionConfig } from './datasource-created-condition.config';
import { FORMS_DATASOURCE_WORKSPACE_CONTEXT } from '../workspace/datasource-workspace.context-token';

export class FormsDataSourceCreatedCondition
	extends UmbConditionBase<FormsDataSourceCreatedConditionConfig>
	implements UmbExtensionCondition
{
	constructor(
		host: UmbControllerHost,
		args: UmbConditionControllerArguments<FormsDataSourceCreatedConditionConfig>,
	) {
		super(host, args);

    this.consumeContext(FORMS_DATASOURCE_WORKSPACE_CONTEXT, (context) => {
      this.permitted = !context.getIsNew();
    });
	}
}

export default FormsDataSourceCreatedCondition;